import{c as t,Q as n,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"AEC-Bench: A Multimodal Benchmark for Agentic Systems in Architecture, Engineering, and Construction","description":"","frontmatter":{"title":"AEC-Bench: A Multimodal Benchmark for Agentic Systems in Architecture, Engineering, and Construction","authors":"Harsh Mankodiya, Chase Gallik, Theodoros Galanos, Andriy Mulyar","published":"2026-03-31T00:00:00.000Z","source":"https://arxiv.org/abs/2603.29199"},"headers":[],"relativePath":"research/papers/2026-03-31-aec-bench-multimodal-benchmark-agentic-systems.md","filePath":"research/papers/2026-03-31-aec-bench-multimodal-benchmark-agentic-systems.md","lastUpdated":1779901665000}'),i={name:"research/papers/2026-03-31-aec-bench-multimodal-benchmark-agentic-systems.md"};function o(s,e,l,d,c,g){return n(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="aec-bench-a-multimodal-benchmark-for-agentic-systems-in-architecture-engineering-and-construction" tabindex="-1">AEC-Bench: A Multimodal Benchmark for Agentic Systems in Architecture, Engineering, and Construction <a class="header-anchor" href="#aec-bench-a-multimodal-benchmark-for-agentic-systems-in-architecture-engineering-and-construction" aria-label="Permalink to &quot;AEC-Bench: A Multimodal Benchmark for Agentic Systems in Architecture, Engineering, and Construction&quot;">​</a></h1><p><strong>Authors</strong>: Harsh Mankodiya (<a href="mailto:harsh@nomic.ai" target="_blank" rel="noreferrer">harsh@nomic.ai</a>), Chase Gallik (<a href="mailto:chase@nomic.ai" target="_blank" rel="noreferrer">chase@nomic.ai</a>), Theodoros Galanos (<a href="mailto:theodoros.galanos@aurecongroup.com" target="_blank" rel="noreferrer">theodoros.galanos@aurecongroup.com</a>), Andriy Mulyar (<a href="mailto:andriy@nomic.ai" target="_blank" rel="noreferrer">andriy@nomic.ai</a>)<br><strong>Institutions</strong>: Nomic AI (Mankodiya, Gallik, Mulyar); Aurecon Group (Galanos)<br><strong>Published</strong>: March 31, 2026 (arXiv:2603.29199v1 [cs.AI])<br><strong>Source</strong>: <a href="https://arxiv.org/abs/2603.29199" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.29199</a><br><strong>Code</strong>: <a href="https://github.com/nomic-ai/aec-bench" target="_blank" rel="noreferrer">https://github.com/nomic-ai/aec-bench</a><br><strong>License</strong>: Apache 2</p><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The AEC-Bench is a multimodal benchmark for evaluating agentic systems on real-world tasks in the Architecture, Engineering, and Construction (AEC) domain. The benchmark covers tasks requiring drawing understanding, cross-sheet reasoning, and construction project-level coordination. This report describes the benchmark motivation, dataset taxonomy, evaluation protocol, and baseline results across several domain-specific foundation model harnesses. We use AEC-Bench to identify consistent tools and harness design techniques that uniformly improve performance across foundation models in their own base harnesses, such as Claude Code and Codex. We openly release our benchmark dataset, agent harness, and evaluation code for full replicability at <a href="https://github.com/nomic-ai/aec-bench" target="_blank" rel="noreferrer">https://github.com/nomic-ai/aec-bench</a> under an Apache 2 license.</p><hr><h2 id="_1-introduction" tabindex="-1">1 Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1 Introduction&quot;">​</a></h2><p>Foundation models equipped with coding-agent harnesses demonstrate strong capabilities in software engineering workflows, where agents can search repositories, edit code, and verify outputs through tool use. These systems rely on structured, verifiable environments and well-defined execution primitives, which enable reliable multi-step reasoning and self-correction. As a result, such harnesses are considered a recipe for building capable agents across new data and task domains.</p><p>Tasks across architecture, engineering, and construction require multimodal understanding, presenting unique challenges to building reliable agents. For example, a single construction drawing sheet contains tightly packed annotations, callouts, line work, and cross-references that require visual reasoning. Agents in construction require access to information that is distributed across highly multimodal documents, resulting in the failure of tools like text search.</p><p>Standard tools in popular agent harnesses, such as text extraction, flatten spatial structure, while vision-based tools lack the quality needed for reliable geometric reasoning. As a result, agents applied to construction tasks often retrieve incomplete or incorrect context, leading to compounding errors. To study these limitations, we built AEC-Bench, a multimodal benchmark to evaluate agentic systems in real-world architecture, engineering, and construction workflows. The benchmark consists of a scaffolded collection of tasks drawn from coordination practices, including intra-sheet review, cross-sheet navigation, and project-level document alignment. We evaluate state-of-the-art coding-agent harnesses on this benchmark to characterize where they succeed, where they fail, and how domain-specific tooling affects performance.</p><h3 id="_1-1-contributions" tabindex="-1">1.1 Contributions <a class="header-anchor" href="#_1-1-contributions" aria-label="Permalink to &quot;1.1 Contributions&quot;">​</a></h3><ul><li>Introduce AEC-Bench: a multimodal benchmark for agentic systems in engineering and construction, with taxonomy spanning intra-sheet, intra-drawing, and intra-project reasoning</li><li>Utilize domain-experts to curate a benchmark with <strong>196 instances across 9 task families</strong>, grounded in construction coordination workflows with automated evaluation</li><li>Show that general-purpose coding-agents partially generalize to AEC tasks but fail on visual grounding, exhaustive traversal, and cross-document coordination</li><li>Demonstrate that domain-specific tools like parsing improve performance on retrieval-sensitive tasks, but further work is required for grounding and judgment-heavy tasks</li></ul><h3 id="_1-2-related-work" tabindex="-1">1.2 Related Work <a class="header-anchor" href="#_1-2-related-work" aria-label="Permalink to &quot;1.2 Related Work&quot;">​</a></h3><p>AEC-Bench has been developed to help identify and characterize the boundary points of agent performance in high-value construction coordination tasks. These coordination tasks require agents to demonstrate multimodal document understanding and context engineering capabilities over long horizons.</p><p>Recent benchmarks for agentic systems demonstrate that tool use, scaffolding, and verifier design strongly influence measured capabilities:</p><ul><li><strong>SWE-bench</strong> (Jimenez et al., 2024): evaluates agents in software engineering environments (repository navigation, file editing, automated test verification)</li><li><strong>GAIA</strong> (Mialon et al., 2023) and <strong>BFCL</strong> (Patil et al., 2025): multi-step action planning and external tool/function call invocation</li><li><strong>AgentBench</strong> (Liu et al., 2024) and <strong>WebArena</strong> (Zhou et al., 2023): interaction with complex textual artifacts and external resources in multi-step reasoning</li></ul><p>Document understanding benchmarks:</p><ul><li><strong>DocVQA</strong> and <strong>InfographicVQA</strong> (Mathew et al., 2021): visual question answering over documents with tables, forms, and graphical elements</li><li><strong>DUDE</strong> (Landeghem et al., 2023): long documents and multi-page contexts</li><li><strong>MMLongBench-Doc</strong> (Ma et al., 2024), <strong>LongDocURL</strong> (Deng et al., 2025), <strong>MLongDoc</strong> (Chia et al., 2025), <strong>M3DocVQA</strong> (Cho et al., 2025): long-context and multi-document reasoning</li></ul><p>AEC-specific benchmarks:</p><ul><li><strong>(Liang et al., 2026)</strong>: hierarchical benchmark for LLM knowledge evaluation in AEC — measures AEC knowledge and cognitive proficiency (distinct from workflow-level agent performance)</li><li><strong>AECV-Bench</strong> (Kondratenko et al., 2026): multimodal understanding of architectural/engineering drawings (OCR, counting, spatial reasoning, drawing-grounded QA over floor plans); shows models still lack robust drawing literacy for symbol-centric understanding</li></ul><p><strong>Key distinction from prior work</strong>: AEC-Bench evaluates agents in realistic workflows where success depends not only on perception or domain knowledge but also on retrieval, cross-sheet navigation, cross-document reasoning, and structured reporting under an execution harness — closer to workflow evaluation than static knowledge testing or document visual QA.</p><h3 id="_1-3-construction-coordination" tabindex="-1">1.3 Construction Coordination <a class="header-anchor" href="#_1-3-construction-coordination" aria-label="Permalink to &quot;1.3 Construction Coordination&quot;">​</a></h3><p>Physical assets such as bridges, water treatment facilities, and office buildings are designed, engineered, and constructed by skilled professionals. While designers and engineers perform preliminary work in 3D modeling software (Revit, AutoCAD), most stages of design development, coordination, and delivery are coordinated through <strong>2D construction drawing sets</strong> and related documents.</p><p>A drawing set is a multi-page, multimodal instruction package in which meaning is conveyed through structured visual and textual elements: plans, details, callouts, notes, and title blocks.</p><p><strong>Coordination failures</strong> between architects, engineers, and construction teams are often the main drivers of scheduling delays and budget overruns. During pre-construction, design, engineering, and handoff, many delays arise from inconsistencies introduced while authoring and revising drawing sets and project documents. Industry teams rely on standardized review and coordination workflows demanding deep professional experience and multimodal reasoning.</p><h3 id="_1-4-task-taxonomy" tabindex="-1">1.4 Task Taxonomy <a class="header-anchor" href="#_1-4-task-taxonomy" aria-label="Permalink to &quot;1.4 Task Taxonomy&quot;">​</a></h3><p>Tasks organized by scope of context required:</p><p><strong>Intra-Sheet</strong>: Tasks completable using a single sheet (one PDF page). Include checking whether callouts match referenced elements, verifying detail titles, or reviewing local assemblies. Focus on understanding what is present on the page and correctly interpreting relationships between text and multimodal drawing elements.</p><p><strong>Intra-Drawing</strong>: Tasks requiring reasoning across multiple sheets within the same drawing set. Examples: validating cross-references, comparing sheet indices, tracing details across views (2D cross-sections of 3D building models). Require navigating between pages and tracking related information.</p><p><strong>Intra-Project</strong>: Tasks involving multiple documents (drawings, specifications, submittals). Include identifying conflicts between specifications and drawings, or evaluating compliance across sources. Reflect real project-level coordination where relevant information is distributed across different documents.</p><h3 id="_1-5-task-formulation" tabindex="-1">1.5 Task Formulation <a class="header-anchor" href="#_1-5-task-formulation" aria-label="Permalink to &quot;1.5 Task Formulation&quot;">​</a></h3><p>Each AEC-Bench task instance consists of:</p><ul><li><strong>Natural-language instruction</strong></li><li><strong>Sandboxed execution environment</strong> (real construction documents from public-sector projects + pre-installed PDF utilities)</li><li><strong>Automated verifier</strong></li></ul><p>Tasks are defined using the <strong>Harbor task format</strong> and executed within the <strong>Harbor harness</strong> (Harbor Framework Team, 2026), which provides a consistent interface for agent interaction and supports tool-based execution through terminal-style commands. Agents must explore the document set, retrieve relevant information, and produce structured findings in a standardized JSONL output file.</p><p><strong>Scoring</strong>: Full credit for complete and correct findings; partial credit for partially correct outputs; zero credit for incorrect or unsupported results.</p><h3 id="_1-6-aec-bench-multimodal-subset" tabindex="-1">1.6 AEC-Bench Multimodal Subset <a class="header-anchor" href="#_1-6-aec-bench-multimodal-subset" aria-label="Permalink to &quot;1.6 AEC-Bench Multimodal Subset&quot;">​</a></h3><p><strong>Construction method</strong>: Semi-automated pipeline combining expert-authored task templates with structured extraction from real-world drawing packages sourced from publicly available PDF documents, spanning multiple disciplines (architectural, structural, civil, mechanical, electrical, plumbing).</p><p>The PDF toolchain breaks multi-page documents into structured, machine-readable data: text with layout information, geometric regions, and cross-sheet references. Domain experts then select target pages/regions and inject <strong>realistic, precisely localized artifacts</strong>:</p><ul><li>Mismatched callout labels</li><li>Broken cross-reference targets</li><li>Swapped specification values</li></ul><p>Using <strong>alignment-aware text editing</strong> that preserves visual fidelity. Each injected artifact is verified with text-level assertions and pixel-level differencing (before, after, and diff).</p><p><strong>Final subset</strong>: <strong>196 task instances</strong> across <strong>9 task types</strong> and <strong>3 scopes</strong>.</p><hr><h2 id="dataset-summary-table-1" tabindex="-1">Dataset Summary (Table 1) <a class="header-anchor" href="#dataset-summary-table-1" aria-label="Permalink to &quot;Dataset Summary (Table 1)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Task</th><th>Description</th><th>Instances</th></tr></thead><tbody><tr><td><strong>Intra-Sheet</strong></td><td>detail-technical-review</td><td>Answer localized technical questions about details</td><td>14</td></tr><tr><td></td><td>detail-title-accuracy</td><td>Verify whether detail titles match the drawn content</td><td>15</td></tr><tr><td></td><td>note-callout-accuracy</td><td>Verify whether callout text correctly describes the referenced element</td><td>14</td></tr><tr><td><strong>Intra-Drawing</strong></td><td>cross-reference-resolution</td><td>Identify cross-references that do not resolve to valid targets</td><td>51</td></tr><tr><td></td><td>cross-reference-tracing</td><td>Find all source locations referencing a given target detail</td><td>24</td></tr><tr><td></td><td>sheet-index-consistency</td><td>Compare sheet index entries against title blocks for mismatches</td><td>14</td></tr><tr><td><strong>Intra-Project</strong></td><td>drawing-navigation</td><td>Locate the correct file, sheet, and detail given a query</td><td>12</td></tr><tr><td></td><td>spec-drawing-sync</td><td>Identify conflicts between specifications and drawings</td><td>16</td></tr><tr><td></td><td>submittal-review</td><td>Evaluate submittals for compliance with specs and drawings</td><td>36</td></tr><tr><td><strong>Total</strong></td><td></td><td></td><td><strong>196</strong></td></tr></tbody></table><hr><h2 id="_2-baseline-agent-evaluation-set-up" tabindex="-1">2 Baseline Agent Evaluation Set-up <a class="header-anchor" href="#_2-baseline-agent-evaluation-set-up" aria-label="Permalink to &quot;2 Baseline Agent Evaluation Set-up&quot;">​</a></h2><p>We evaluate agent performance using baseline harness configurations designed to isolate the impact of tool access, document representation, and domain-specific augmentation. Rather than comparing foundation models in isolation, our goal is to understand how harness design shapes performance on AEC tasks.</p><p><strong>Two harness families</strong>: Codex and Claude Code</p><p><strong>Two configurations</strong>:</p><ul><li><p><strong>H (base)</strong>: sandboxed environment with terminal (Bash) access + standard utilities for navigating document space (CLI-based PDF tools: pdftotext, pdftoppm). Agents may also write and execute their own code to process documents, create intermediate cache files, and perform operations such as searching across multiple files.</p></li><li><p><strong>H+ (enhanced)</strong>: base + domain-specific <strong>Nomic tools</strong> (Nomic Parse, Nomic Embeddings). Provides structured representations of drawings including extracted text, layout elements, and reference relationships.</p></li></ul><p><strong>Models tested</strong>:</p><ul><li>Codex: GPT-5.4, GPT-5.2</li><li>Claude Code: Opus 4.6, Sonnet 4.6</li><li>Nomic Agent (baseline)</li></ul><hr><h2 id="_3-results-table-2-mean-reward-by-task-model-and-setup" tabindex="-1">3 Results (Table 2: Mean Reward by Task, Model, and Setup) <a class="header-anchor" href="#_3-results-table-2-mean-reward-by-task-model-and-setup" aria-label="Permalink to &quot;3 Results (Table 2: Mean Reward by Task, Model, and Setup)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Task</th><th style="text-align:center;">GPT-5.4 H</th><th style="text-align:center;">GPT-5.4 H+</th><th style="text-align:center;">GPT-5.2 H</th><th style="text-align:center;">GPT-5.2 H+</th><th style="text-align:center;">Opus 4.6 H</th><th style="text-align:center;">Opus 4.6 H+</th><th style="text-align:center;">Sonnet 4.6 H</th><th style="text-align:center;">Sonnet 4.6 H+</th></tr></thead><tbody><tr><td><strong>Intra-Sheet</strong></td><td>detail-technical-review</td><td style="text-align:center;">35.7</td><td style="text-align:center;">71.4</td><td style="text-align:center;">60.7</td><td style="text-align:center;">85.7</td><td style="text-align:center;">35.7</td><td style="text-align:center;">78.6</td><td style="text-align:center;">53.6</td><td style="text-align:center;">78.6</td></tr><tr><td></td><td>detail-title-accuracy</td><td style="text-align:center;">60.0</td><td style="text-align:center;">60.0</td><td style="text-align:center;">60.0</td><td style="text-align:center;">40.0</td><td style="text-align:center;">46.7</td><td style="text-align:center;">73.3</td><td style="text-align:center;">86.7</td><td style="text-align:center;">73.3</td></tr><tr><td></td><td>note-callout-accuracy</td><td style="text-align:center;">28.6</td><td style="text-align:center;">28.6</td><td style="text-align:center;">28.6</td><td style="text-align:center;">14.3</td><td style="text-align:center;">0.0</td><td style="text-align:center;">35.7</td><td style="text-align:center;">42.9</td><td style="text-align:center;">35.7</td></tr><tr><td><strong>Intra-Drawing</strong></td><td>cross-reference-resolution</td><td style="text-align:center;">84.3</td><td style="text-align:center;">77.5</td><td style="text-align:center;">61.0</td><td style="text-align:center;">67.6</td><td style="text-align:center;">79.0</td><td style="text-align:center;">72.5</td><td style="text-align:center;">73.9</td><td style="text-align:center;">68.6</td></tr><tr><td></td><td>sheet-index-consistency</td><td style="text-align:center;">97.6</td><td style="text-align:center;">81.9</td><td style="text-align:center;">82.1</td><td style="text-align:center;">85.0</td><td style="text-align:center;">71.4</td><td style="text-align:center;">85.5</td><td style="text-align:center;">72.6</td><td style="text-align:center;">76.0</td></tr><tr><td></td><td>cross-reference-tracing</td><td style="text-align:center;">89.2</td><td style="text-align:center;">77.1</td><td style="text-align:center;">79.5</td><td style="text-align:center;">73.8</td><td style="text-align:center;">56.4</td><td style="text-align:center;">62.0</td><td style="text-align:center;">59.2</td><td style="text-align:center;">69.3</td></tr><tr><td><strong>Intra-Project</strong></td><td>spec-drawing-sync</td><td style="text-align:center;">55.0</td><td style="text-align:center;">71.8</td><td style="text-align:center;">44.0</td><td style="text-align:center;">50.0</td><td style="text-align:center;">29.0</td><td style="text-align:center;">51.3</td><td style="text-align:center;">26.0</td><td style="text-align:center;">64.1</td></tr><tr><td></td><td>drawing-navigation</td><td style="text-align:center;">66.7</td><td style="text-align:center;">100.0</td><td style="text-align:center;">83.3</td><td style="text-align:center;">83.3</td><td style="text-align:center;">75.0</td><td style="text-align:center;">100.0</td><td style="text-align:center;">75.0</td><td style="text-align:center;">91.7</td></tr><tr><td></td><td>submittal-review</td><td style="text-align:center;">15.0</td><td style="text-align:center;">19.0</td><td style="text-align:center;">11.8</td><td style="text-align:center;">19.0</td><td style="text-align:center;">17.1</td><td style="text-align:center;">16.7</td><td style="text-align:center;">6.5</td><td style="text-align:center;">23.1</td></tr></tbody></table><p><strong>Key numbers by task (H → H+ average gain across all models)</strong>:</p><ul><li>detail-technical-review: <strong>+32.2%</strong> (retrieval-sensitive, largest gain)</li><li>spec-drawing-sync: <strong>+20.8%</strong></li><li>drawing-navigation: <strong>+18.75%</strong></li><li>note-callout-accuracy: <strong>-3.6%</strong> (degradation — visual-spatial grounding task)</li><li>cross-reference-resolution: <strong>-2.4%</strong> (degradation — exhaustive traversal task)</li><li>submittal-review: best score only <strong>23.1</strong> (lowest across all configurations)</li></ul><hr><h2 id="_4-discussion" tabindex="-1">4 Discussion <a class="header-anchor" href="#_4-discussion" aria-label="Permalink to &quot;4 Discussion&quot;">​</a></h2><h3 id="_4-1-retrieval-as-primary-bottleneck" tabindex="-1">4.1 Retrieval as Primary Bottleneck <a class="header-anchor" href="#_4-1-retrieval-as-primary-bottleneck" aria-label="Permalink to &quot;4.1 Retrieval as Primary Bottleneck&quot;">​</a></h3><p>A central finding: multimodal AEC tasks tightly couple retrieval and reasoning, with <strong>retrieval frequently acting as the primary bottleneck</strong>. Agents often fail before reaching the core reasoning step because they cannot reliably locate the relevant sheet, detail, or document; once the correct context is retrieved, performance improves substantially.</p><p>Evidence from Table 2 H+ vs H:</p><ul><li>detail-technical-review: +32.2 points avg across models</li><li>spec-drawing-sync: +20.8 points avg</li><li>drawing-navigation: +18.75 points avg</li></ul><p>These tasks are characterized by a primary dependence on locating the correct sheet, detail, or document before reasoning can proceed.</p><h3 id="_4-2-targeted-benefits-—-not-uniform-gains" tabindex="-1">4.2 Targeted Benefits — Not Uniform Gains <a class="header-anchor" href="#_4-2-targeted-benefits-—-not-uniform-gains" aria-label="Permalink to &quot;4.2 Targeted Benefits — Not Uniform Gains&quot;">​</a></h3><p>Document parsing provides targeted benefits rather than uniform gains. On tasks relying more heavily on visual-spatial grounding:</p><ul><li>note-callout-accuracy: <strong>-3.6%</strong> avg (degradation)</li><li>cross-reference-resolution: <strong>-2.4%</strong> (degradation)</li><li>sheet-index-consistency: <strong>-0.1%</strong> (degradation)</li><li>cross-reference-tracing: <strong>-0.53%</strong> (degradation)</li></ul><p><strong>Reason</strong>: These tasks require precise localization, alignment between text and geometry. The model must trace leader lines and related geometry purely visually to correctly identify and report issues. Even when relevant evidence might exist from parsing, agents frequently fail to localize it accurately. Adding parsed PDF representations does not directly address the underlying gap and can instead introduce additional context that the agent must navigate.</p><h3 id="_4-3-tool-call-execution-patterns" tabindex="-1">4.3 Tool Call Execution Patterns <a class="header-anchor" href="#_4-3-tool-call-execution-patterns" aria-label="Permalink to &quot;4.3 Tool Call Execution Patterns&quot;">​</a></h3><p>Despite operating on multimodal construction documents, models consistently default to a coding-oriented tool repertoire:</p><table tabindex="0"><thead><tr><th>Metric</th><th style="text-align:center;">Codex (GPT-5.x)</th><th style="text-align:center;">Claude (Opus/Sonnet)</th></tr></thead><tbody><tr><td>Bash usage</td><td style="text-align:center;"><strong>100%</strong></td><td style="text-align:center;">53%</td></tr><tr><td>Read operations</td><td style="text-align:center;">—</td><td style="text-align:center;">35%</td></tr><tr><td>pdftotext calls</td><td style="text-align:center;">77% across all models</td><td style="text-align:center;"></td></tr><tr><td>pdftoppm (image rendering)</td><td style="text-align:center;"><strong>96%</strong></td><td style="text-align:center;">32%</td></tr></tbody></table><p><strong>Key finding</strong>: 77% of trajectories invoke pdftotext — strong convergence toward a pdftotext extraction pipeline. While this enables efficient keyword-based search, it collapses spatial layout and geometric relationships into linear text, discarding critical visual structure.</p><p>Codex agents rely heavily on rasterization via pdftoppm (96%), whereas Claude agents use it far less (32%). Yet this increased use of image rendering does not lead to better performance on visually grounded tasks — access to images alone is insufficient without the ability to interpret spatial relationships.</p><h3 id="_4-4-failure-mode-analysis" tabindex="-1">4.4 Failure Mode Analysis <a class="header-anchor" href="#_4-4-failure-mode-analysis" aria-label="Permalink to &quot;4.4 Failure Mode Analysis&quot;">​</a></h3><p><strong>note-callout-accuracy breakdown</strong> (14 instances × 4 models = 56 total runs, separated into):</p><table tabindex="0"><thead><tr><th>Subcategory</th><th style="text-align:center;">Instances</th><th style="text-align:center;">Avg Reward</th></tr></thead><tbody><tr><td>Text-catchable</td><td style="text-align:center;">2</td><td style="text-align:center;">~100%</td></tr><tr><td>Visual-required</td><td style="text-align:center;">10</td><td style="text-align:center;">~5%</td></tr></tbody></table><p>&quot;This large gap highlights a consistent failure mode: tasks that depend on tracing and geometric interpretation remain challenging for current systems, even under identical task structures and tool availability.&quot;</p><p>Failures are not due to lack of access to visual information — trajectories show extensive image rendering and inspection — but rather an inability to <strong>translate visual input into structured, spatially grounded judgments</strong>.</p><h3 id="_4-5-submittal-review-failure-mode" tabindex="-1">4.5 Submittal-Review Failure Mode <a class="header-anchor" href="#_4-5-submittal-review-failure-mode" aria-label="Permalink to &quot;4.5 Submittal-Review Failure Mode&quot;">​</a></h3><p>submittal-review shows a distinct failure mode — consistently low performance across all models and setups (best reward: 23.1):</p><ul><li>Parse improves access to relevant text, but does not resolve the need for <strong>higher-level judgment</strong></li><li>Agents tend to <strong>over-generate findings</strong>, leading to high false positive rates</li><li>Requires domain-specific judgment and prioritization consistent with <strong>professional review standards</strong></li><li>Evaluation is inherently more sensitive to human interpretation, increasing likelihood of disagreement with verifier</li></ul><h3 id="_4-6-limitations" tabindex="-1">4.6 Limitations <a class="header-anchor" href="#_4-6-limitations" aria-label="Permalink to &quot;4.6 Limitations&quot;">​</a></h3><ul><li>Limited number of documents and subset of tasks per category/discipline — may constrain statistical robustness and coverage</li><li>Tasks do not fully capture the breadth of abilities exhibited by modern LLM harnesses</li><li>Some task families rely on curated artifacts or controlled defects that may not reflect full diversity of real-world drawing sets</li><li>Most tasks rely on deterministic evaluation (keyword matching) — may not fully capture nuanced human judgments of engineering correctness</li><li>Scope may not fully reflect the diversity of real-world AEC drawing sets</li></ul><h3 id="_4-7-replicability-and-license" tabindex="-1">4.7 Replicability and License <a class="header-anchor" href="#_4-7-replicability-and-license" aria-label="Permalink to &quot;4.7 Replicability and License&quot;">​</a></h3><p>Benchmark, agent harnesses, and evaluation code available at <a href="https://github.com/Nomic-ai/aec-bench" target="_blank" rel="noreferrer">https://github.com/Nomic-ai/aec-bench</a> under Apache 2 license.</p><hr><h2 id="_5-conclusion" tabindex="-1">5 Conclusion <a class="header-anchor" href="#_5-conclusion" aria-label="Permalink to &quot;5 Conclusion&quot;">​</a></h2><p>AEC-Bench introduces a benchmark for evaluating multimodal, agentic reasoning in construction-document coordination workflows grounded in real-world design and engineering practices. By framing tasks around common review activities (reference tracing, navigation, coordination across drawings and specifications), it reflects the structure and demands of practical AEC coordination workflows, with outputs graded by domain-experts.</p><p><strong>Core conclusions</strong>:</p><ol><li><strong>Multimodal data representation and context engineering</strong> are central to AEC agent performance</li><li><strong>Coding-agent systems transfer meaningfully</strong> to this domain, particularly for retrieval and structured reasoning tasks</li><li>Performance becomes <strong>less consistent</strong> in settings requiring spatial grounding or domain-sensitive judgment</li><li><strong>Neither visual inputs nor structured document parsing is sufficient in isolation</strong> — effective performance emerges from how modalities are coordinated and surfaced within the agent loop</li><li>Points to the importance of <strong>domain-aware system design</strong> where multiple capabilities are orchestrated to match task demands</li></ol><h3 id="future-directions" tabindex="-1">Future Directions <a class="header-anchor" href="#future-directions" aria-label="Permalink to &quot;Future Directions&quot;">​</a></h3><ul><li><strong>Scale and diversity expansion</strong>: larger drawing sets, more disciplines, additional task families</li><li><strong>Improved evaluation methodology</strong>: verifiers capable of assessing evidence grounding and reasoning steps (beyond keyword matching)</li><li><strong>Domain-specific agent architectures</strong>: systems designed for document navigation — iteratively exploring drawing sets, maintaining spatial memory on sheets, retrieving evidence regions prior to reasoning</li><li><strong>Stronger domain knowledge integration</strong>: incorporating domain expertise into multimodal models for tasks requiring engineering judgment</li></ul><hr><h2 id="figures" tabindex="-1">Figures <a class="header-anchor" href="#figures" aria-label="Permalink to &quot;Figures&quot;">​</a></h2><p><strong>Figure 1</strong>: Mean reward by AEC-Bench category — bar chart showing performance across Intra-Sheet, Intra-Drawing, Intra-Project for each model/setup combination.</p><p><strong>Figure 2</strong>: Example of a complex construction drawing PDF page — a visually dense drawing sheet with tightly packed annotations, callouts, and linework typical of real construction coordination artifacts.</p><p><strong>Figure 3</strong>: Representative before/after task snapshots used in data preparation:</p><ul><li><strong>Top row (cross-reference resolution)</strong>: before/after showing subtle reference-number inconsistencies requiring cross-sheet verification</li><li><strong>Bottom row (note-callout accuracy)</strong>: before/after showing callout text change while preserving surrounding geometry and leader structure — tests precise text-to-geometry grounding</li></ul><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><p>Yew Ken Chia, Liying Cheng, Hou Pong Chan, et al. 2025. M-LongDoc: A benchmark for multimodal super-long document understanding and a retrieval-aware tuning framework. In <em>EMNLP 2025</em>, pages 9233–9250.</p><p>Jaemin Cho, Debanjan Mahata, Ozan Irsoy, Yujie He, and Mohit Bansal. 2025. M3DocVQA: Multi-modal multi-page multi-document understanding. In <em>ICCV 2025</em>, pages 6178–6188.</p><p>Chao Deng, Jiale Yuan, Pi Bu, et al. 2025. LongDocURL: A comprehensive multimodal long document benchmark integrating understanding, reasoning, and locating.</p><p>Theodoros Galanos. 2026. Benchmarking agents on real engineering work is already teaching us something important. The Harness Blog.</p><p>Harbor Framework Team. 2026. Harbor: A framework for evaluating and optimizing agents and models in container environments.</p><p>Carlos E. Jimenez, John Yang, Alexander Wettig, Shunyu Yao, Kexin Pei, Ofir Press, and Karthik R. Narasimhan. 2024. SWE-bench: Can language models resolve real-world GitHub issues? In <em>ICLR 2024</em>.</p><p>Aleksei Kondratenko, Mussie Birhane, Houssame E. Hsain, and Guido Maciocci. 2026. AECV-Bench: Benchmarking multimodal models on architectural and engineering drawings understanding.</p><p>Jordy Van Landeghem, Ruben Tito, Łukasz Borchmann, et al. 2023. Document understanding dataset and evaluation (DUDE).</p><p>Chen Liang, Zhaoqi Huang, Haofen Wang, et al. 2026. AECBench: A hierarchical benchmark for knowledge evaluation of large language models in the AEC field. <em>Advanced Engineering Informatics</em>, 71:104314.</p><p>Xiao Liu, Hao Yu, Hanchen Zhang, et al. 2024. AgentBench: Evaluating LLMs as agents. In <em>ICLR 2024</em>.</p><p>Antonio Loison, Quentin Macé, Antoine Edy, et al. 2026. ViDoRe v3: A comprehensive evaluation of retrieval augmented generation in complex real-world scenarios.</p><p>Yubo Ma, Yuhang Zang, Liangyu Chen, et al. 2024. MMLongBench-Doc: Benchmarking long-context document understanding with visualizations.</p><p>Ahmed Masry, Do Xuan Long, Jia Qing Tan, Shafiq Joty, and Enamul Hoque. 2022. ChartQA: A benchmark for question answering about charts with visual and logical reasoning. In <em>ACL 2022 Findings</em>, pages 2263–2279.</p><p>Minesh Mathew, Dimosthenis Karatzas, and C. V. Jawahar. 2021. DocVQA: A dataset for VQA on document images.</p><p>Grégoire Mialon, Clémentine Fourrier, Craig Swift, Thomas Wolf, Yann LeCun, and Yann Scialom. 2023. GAIA: A benchmark for general AI assistants.</p><p>Zach Nussbaum, John X. Morris, Brandon Duderstadt, and Andriy Mulyar. 2025. Nomic Embed: Training a reproducible long context text embedder.</p><p>Shishir G. Patil, Huanzhi Mao, Fanjia Yan, et al. 2025. The Berkeley Function Calling Leaderboard (BFCL): From tool use to agentic evaluation of large language models. In <em>ICML 2025</em>.</p><p>Xiang Yue, Yuansheng Ni, Kai Zhang, et al. 2024. MMMU: A massive multi-discipline multimodal understanding and reasoning benchmark for expert AGI.</p><p>Shuyan Zhou, Frank F. Xu, Hao Zhu, et al. 2023. WebArena: A realistic web environment for building autonomous agents. <em>arXiv:2307.13854</em>.</p><p>Yifan Zhou et al. 2024. DocPrompting: Generating chain-of-thought prompts for document understanding.</p><hr><p><strong>Keywords</strong>: AEC, multimodal benchmark, agent evaluation, construction coordination, document understanding, retrieval-augmented agents, Harbor framework, visual grounding, cross-reference resolution</p>',121)])])}const m=t(i,[["render",o]]);export{h as __pageData,m as default};
